39	        packets.add(ILensProtocol.createVelocityPacket(velocityScaled));
40	        packets.add(ILensProtocol.createHeartRatePacket(hrSlotValue));
41	        packets.add(ILensProtocol.createCadencePacket(values.altitudeM));
