109	    private var _savedDeviceScanAttempts as Lang.Number = 0; // 저장된 기기 탐색 시도 횟수
110	    private const SCAN_TIMEOUT_MS_IQ = 3000;                 // 스캔 타임아웃 (ms)
111	
112	    //! FR55 호환성: Profile을 lazy 생성 (파일 로드 시 BLE API 호출 방지)
113	    private function getExerciseProfile() as Lang.Dictionary {
114	        return {
115	            :uuid => BluetoothLowEnergy.stringToUuid("4b329cf2-3816-498c-8453-ee8798502a08"),
116	            :characteristics => [
117	                { :uuid => BluetoothLowEnergy.stringToUuid("c259c1bd-18d3-c348-b88d-5447aea1b615") }
118	            ]
119	        };
120	    }
121	
122	    //! Constructor
123	    function initialize() {
124	        DataField.initialize();
125	
126	        // BLE Delegate 설정 (별도 클래스 필요 - DataField는 BleDelegate 상속 불가)
127	        try {
128	            var delegate = new $.RunVisionBleDelegate(self);
129	            BluetoothLowEnergy.setDelegate(delegate);
130	
131	            // 초기화 시 기존 bonding 정보 삭제 (iLens는 multi-bonding 미지원)
132	            // FR55 호환성: has 연산자로 API 존재 여부 확인
133	            if (BluetoothLowEnergy has :getPairedDevices) {
134	                try {
135	                    var paired = BluetoothLowEnergy.getPairedDevices();
136	                    var dev = paired.next() as BluetoothLowEnergy.Device;
137	                    while (dev != null) {
138	                        BluetoothLowEnergy.unpairDevice(dev);
139	                        dev = paired.next() as BluetoothLowEnergy.Device;
140	                    }
141	                } catch (ex2) {
142	                    // 무시
143	                }
144	            }
145	
146	            _scanStatus = "INIT_OK";
147	            addBleLog("READY");
148	        } catch (ex) {
149	            _scanStatus = "INIT_ERR";
150	            addBleLog("ERR:init");
151	        }
152	
153	        _metricValues = new MetricValues();
154	    }
155	
